from pathlib import Path
import os

def delete_uploaded_file(file_id, file_mapping, base_dir='uploads'):
    # Ensure base_dir is an absolute path
    base_dir = Path(base_dir).resolve()

    # Get the file path from the server-side mapping
    if file_id not in file_mapping:
        raise ValueError("Invalid file ID")

    user_path = file_mapping[file_id]

    # Resolve the full path and ensure it's within the base directory
    full_path = (base_dir / user_path).resolve()
    if not full_path.is_file() or not str(full_path).startswith(str(base_dir)):
        raise ValueError("Invalid file path")

    # Delete the file
    os.remove(full_path)

